fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let bypass = required_bool(params, "bypass").map_err(anyhow::Error::msg)?;
    let level_in = required_f32(params, "level_in").map_err(anyhow::Error::msg)?;
    let level_out = required_f32(params, "level_out").map_err(anyhow::Error::msg)?;
    let bits = required_f32(params, "bits").map_err(anyhow::Error::msg)?;
    let morph = required_f32(params, "morph").map_err(anyhow::Error::msg)?;
    let mode = required_f32(params, "mode").map_err(anyhow::Error::msg)?;
    let dc = required_f32(params, "dc").map_err(anyhow::Error::msg)?;
    let anti_aliasing = required_f32(params, "anti_aliasing").map_err(anyhow::Error::msg)?;
    let samples = required_f32(params, "samples").map_err(anyhow::Error::msg)?;
    let lfo = required_bool(params, "lfo").map_err(anyhow::Error::msg)?;
    let lforange = required_f32(params, "lforange").map_err(anyhow::Error::msg)?;
    let lforate = required_f32(params, "lforate").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_BYPASS, if bypass { 1.0 } else { 0.0 }),
        (PORT_CTRL_LEVEL_IN, level_in),
        (PORT_CTRL_LEVEL_OUT, level_out),
        (PORT_CTRL_BITS, bits),
        (PORT_CTRL_MORPH, morph),
        (PORT_CTRL_MODE, mode),
        (PORT_CTRL_DC, dc),
        (PORT_CTRL_ANTI_ALIASING, anti_aliasing),
        (PORT_CTRL_SAMPLES, samples),
        (PORT_CTRL_LFO, if lfo { 1.0 } else { 0.0 }),
        (PORT_CTRL_LFORANGE, lforange),
        (PORT_CTRL_LFORATE, lforate),
    ];

    let processor = lv2::build_stereo_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN_L, PORT_AUDIO_IN_IN_R], &[PORT_AUDIO_OUT_OUT_L, PORT_AUDIO_OUT_OUT_R], control_ports)?;
    let _ = layout;
    Ok(BlockProcessor::Stereo(Box::new(processor)))
}

